                          <tr>\r\n                                <th>Tipo de documento</th>\r\n                                <th>Número</th>\r\n                                <th class=\"text-center\">D. Contingencia</th>\r\n                                <th></th>\r\n                            </tr>\r\n                            </thead>\r\n                            <tbody>\r\n                            <tr v-for=\"(row, index) in records\" :key=\"index\">\r\n                                <template v-if=\"row.id\">\r\n                                    <td>{{ row.document_type_description }}</td>\r\n                                    <td>{{ row.number }}</td>\r\n                                    <td class=\"text-center\">{{ (row.contingency) ? \"SI\" : \"NO\" }}</td>\r\n                                    <td class=\"series-table-actions text-end\">\r\n                                        <button type=\"button\" class=\"btn waves-effect waves-light btn-sm btn-danger\" @click.prevent=\"clickDelete(row.id)\">Eliminar</button>\r\n                                        <!--<el-button type=\"danger\" icon=\"el-icon-delete\" plain @click.prevent=\"clickDelete(row.id)\"></el-button>-->\r\n                                    </td>\r\n                                </template>\r\n                                <template v-else>\r\n                                    <td>\r\n                                        <div class=\"form-group mb-0\" :class=\"{'has-danger': row.errors.document_type_id}\">\r\n                                            <el-select v-model=\"row.document_type_id\">\r\n                                                <el-option v-for=\"option in document_types\" :key=\"option.id\" :value=\"option.id\" :label=\"option.description\"></el-option>\r\n                                            </el-select>\r\n                                            <small class=\"form-control-feedback\" v-if=\"row.errors.document_type_id\" v-text=\"row.errors.document_type_id[0]\"></small>\r\n                                        </div>\r\n                                    </td>\r\n                                    <td>\r\n                                        <div class=\"form-group mb-0\" :class=\"{'has-danger': row.errors.number}\">\r\n                                            <el-input v-model=\"row.number\" :maxlength=\"4\"> <i slot=\"prefix\" class=\"el-icon-edit-outline\"></i></el-input>\r\n                                            <small class=\"form-control-feedback\" v-if=\"row.errors.number\" v-text=\"row.errors.number[0]\"></small>\r\n                                        </div>\r\n                                    </td>\r\n                                    <td>\r\n                                        <div class=\"col-md-3 center-el-checkbox\">\r\n                                            <div class=\"form-group\" :class=\"{'has-danger': row.errors.contingency}\">\r\n                                                <el-checkbox v-model=\"row.contingency\" @change=\"filterDocumentType(row)\">Contingencia</el-checkbox>\r\n                                                <small class=\"form-control-feedback\" v-if=\"row.errors.contingency\" v-text=\"row.errors.contingency[0]\"></small>\r\n                                            </div>\r\n                                        </div>\r\n                                    </td>\r\n                                    <td class=\"series-table-actions text-end\">\r\n                                        <button type=\"button\" class=\"btn waves-effect waves-light btn-sm btn-info\" @click.prevent=\"clickSubmit(index)\">\r\n                                            <i class=\"fa fa-check\"></i>\r\n                                        </button>\r\n                                        <button type=\"button\" class=\"btn waves-effect waves-light btn-sm btn-danger\" @click.prevent=\"clickCancel(index)\">\r\n                                            <i class=\"fa fa-trash\"></i>\r\n                                        </button>\r\n                                    </td>\r\n                                </template>\r\n                            </tr>\r\n                            </tbody>\r\n                        </table>\r\n                    </div>\r\n                </div>\r\n                <div class=\"col-md-12 text-center pt-2\" v-if=\"showAddButton\">\r\n                    <el-button type=\"primary\" icon=\"el-icon-plus\" @click=\"clickAddRow\">Nuevo</el-button>\r\n                </div>\r\n            </div>\r\n        </div>\r\n    </el-dialog>\r\n\r\n</template>\r\n\r\n<script>\r\n\r\n    import {deletable} from '../../../mixins/deletable'\r\n\r\n    export default {\r\n        props: ['showDialog', 'establishmentId'],\r\n        mixins: [deletable],\r\n        data() {\r\n            return {\r\n                resource: 'series',\r\n                records: [],\r\n                document_types: [],\r\n                all_document_types: [],\r\n                showAddButton: true,\r\n            }\r\n        },\r\n        async created() {\r\n            await this.initForm()\r\n            await this.$http.get(`/${this.resource}/tables`)\r\n                .then(response => {\r\n                    this.all_document_types = response.data.document_types\r\n                    this.initDocumentTypes()\r\n                })\r\n        },\r\n        methods: {\r\n            initForm() {\r\n                this.records = []\r\n                this.showAddButton = true\r\n            },\r\n            async getData() {\r\n                if (this.establishmentId) {\r\n                    await this.$http.get(`/${this.resource}/records/${this.establishmentId}`)\r\n                        .then(response => {\r\n                            if (response.data !== '') {\r\n                                this.records = response.data.data\r\n                            }\r\n                        })\r\n                }\r\n            },\r\n            clickAddRow() {\r\n                this.records.push({\r\n                    id: null,\r\n                    document_type_id: null,\r\n                    number: null,\r\n                    contingency: false,\r\n                    errors: {},\r\n                    loading: false\r\n                })\r\n                this.showAddButton = false\r\n            },\r\n            clickCancel(index) {\r\n                this.records.splice(index, 1)\r\n                this.initDocumentTypes()\r\n                this.showAddButton = true\r\n            },\r\n            clickSubmit(index) {\r\n                let form = {\r\n                    id: this.records[index].id,\r\n                    establishment_id: this.establishmentId,\r\n                    document_type_id: this.records[index].document_type_id,\r\n                    number: this.records[index].number,\r\n                    contingency: this.records[index].contingency,\r\n                }\r\n                this.$http.post(`/${this.resource}`, form)\r\n                    .then(response => {\r\n                        if (response.data.success) {\r\n                            this.$message.success(response.data.message)\r\n                            this.getData()\r\n                            this.initDocumentTypes()\r\n                            this.showAddButton = true\r\n                        } else {\r\n                            this.$message.error(response.data.message)\r\n                        }\r\n                    })\r\n                    .catch(error => {\r\n                        if (error.response.status === 422) {\r\n                            this.records[index].errors = error.response.data\r\n                        } else {\r\n                            console.log(error)\r\n                        }\r\n                    })\r\n            },\r\n            filterDocumentType(row){\r\n\r\n                if(row.contingency){\r\n                    this.document_types = _.filter(this.all_document_types, item => (item.id == '01' || item.id =='03' || item.id =='07' || item.id =='08' || item.id == '09'))\r\n                    row.document_type_id = (this.document_types.length > 0)?this.document_types[0].id:null\r\n                }else{\r\n                    row.document_type_id = null\r\n                    this.document_types = this.all_document_types\r\n                }\r\n            },\r\n            initDocumentTypes(){\r\n                this.document_types = (this.all_document_types.length > 0) ? this.all_document_types : []\r\n            },\r\n            close() {\r\n                this.$emit('update:showDialog', false)\r\n                this.initDocumentTypes()\r\n                this.initForm()\r\n            },\r\n            clickDelete(id) {\r\n                this.destroy(`/${this.resource}/${id}`).then(() =>\r\n                    this.getData(),\r\n                    this.initDocumentTypes()\r\n                )\r\n            }\r\n        }\r\n    }\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/views/establishments/partials/series.vue","<template>\r\n    <el-dialog\r\n        :title=\"titleDialog\"\r\n        :visible=\"showDialog\"\r\n        @close=\"close\"\r\n        @open=\"create\"\r\n    >\r\n        <form autocomplete=\"off\" @submit.prevent=\"submit\">\r\n            <div class=\"form-body\">\r\n                <div class=\"row\">\r\n                    <div class=\"col-md-8\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.description }\"\r\n                        >\r\n                            <label class=\"control-label\">Descripción</label>\r\n                            <el-input v-model=\"form.description\"> </el-input>\r\n                            <small\r\n                                class=\"form-control-feedback\"\r\n                                v-if=\"errors.description\"\r\n                                v-text=\"errors.description[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.code }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Código Domicilio Fiscal</label\r\n                            >\r\n                            <el-input v-model=\"form.code\" :maxlength=\"4\">\r\n                            </el-input>\r\n                            <small\r\n                                class=\"form-control-feedback\"\r\n                                v-if=\"errors.code\"\r\n                                v-text=\"errors.code[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                <div class=\"row\">\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.country_id }\"\r\n                        >\r\n                            <label class=\"control-label\">País</label>\r\n                            <el-select v-model=\"form.country_id\" filterable>\r\n                                <el-option\r\n                                    v-for=\"option in countries\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.description\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"form-control-feedback\"\r\n                                v-if=\"errors.country_id\"\r\n                                v-text=\"errors.country_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.department_id }\"\r\n                        >\r\n                            <label class=\"control-label\">Departamento</label>\r\n                            <el-select\r\n                                v-model=\"form.department_id\"\r\n                                filterable\r\n                                @change=\"filterProvince\"\r\n                            >\r\n                                <el-option\r\n                                    v-for=\"option in all_departments\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.description\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"form-control-feedback\"\r\n                                v-if=\"errors.department_id\"\r\n                                v-text=\"errors.department_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.province_id }\"\r\n                        >\r\n                            <label class=\"control-label\">Provincia</label>\r\n                            <el-select\r\n                                v-model=\"form.province_id\"\r\n                                filterable\r\n                                @change=\"filterDistrict\"\r\n                            >\r\n                                <el-option\r\n                                    v-for=\"option in provinces\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.description\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"form-control-feedback\"\r\n                                v-if=\"errors.province_id\"\r\n                                v-text=\"errors.province_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                <div class=\"row\">\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.province_id }\"\r\n                        >\r\n                            <label class=\"control-label\">Distrito</label>\r\n                            <el-select v-model=\"form.district_id\" filterable>\r\n                                <el-option\r\n                                    v-for=\"option in districts\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.description\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"form-control-feedback\"\r\n                                v-if=\"errors.district_id\"\r\n                                v-text=\"errors.district_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-8\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.address }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Dirección Fiscal</label\r\n                            >\r\n                            <el-input v-model=\"form.address\"> </el-input>\r\n                            <small\r\n                                class=\"form-control-feedback\"\r\n                                v-if=\"errors.address\"\r\n                                v-text=\"errors.address[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                <div class=\"row\">\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.telephone }\"\r\n                        >\r\n                            <label class=\"control-label\">Teléfono</label>\r\n                            <el-input v-model=\"form.telephone\"> </el-input>\r\n                            <small\r\n                                class=\"form-control-feedback\"\r\n                                v-if=\"errors.telephone\"\r\n                                v-text=\"errors.telephone[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-8\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.trade_address }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Dirección Comercial</label\r\n                            >\r\n                            <el-input v-model=\"form.trade_address\"> </el-input>\r\n                            <small\r\n                                class=\"form-control-feedback\"\r\n                                v-if=\"errors.trade_address\"\r\n                                v-text=\"errors.trade_address[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                <div class=\"row\">\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.email }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Correo de contacto</label\r\n                            >\r\n                            <el-input v-model=\"form.email\"> </el-input>\r\n                            <small\r\n                                class=\"form-control-feedback\"\r\n                                v-if=\"errors.email\"\r\n                                v-text=\"errors.email[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-8\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.web_address }\"\r\n                        >\r\n                            <label class=\"control-label\">Dirección web</label>\r\n                            <el-input v-model=\"form.web_address\"> </el-input>\r\n                            <small\r\n                                class=\"form-control-feedback\"\r\n                                v-if=\"errors.web_address\"\r\n                                v-text=\"errors.web_address[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.direct_printing }\"\r\n                        >\r\n                            <h2>\r\n                                <el-switch\r\n                                    v-model=\"form.direct_printing\"\r\n                                    active-text=\"Impresion Directa\"\r\n                                ></el-switch>\r\n                            </h2>\r\n                            <small\r\n                                class=\"form-control-feedback\"\r\n                                v-if=\"errors.direct_printing\"\r\n                                v-text=\"errors.direct_printing[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.printer }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Nombre de Impresora</label\r\n                            >\r\n                            <el-input v-model=\"form.printer\"> </el-input>\r\n                            <small\r\n                                class=\"form-control-feedback\"\r\n                                v-if=\"errors.printer\"\r\n                                v-text=\"errors.printer[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.copies }\"\r\n                        >\r\n                            <label class=\"control-label\">Nº Copiassssss </label>\r\n                            <el-input v-model=\"form.copies\"> </el-input>\r\n                            <small\r\n                                class=\"form-control-feedback\"\r\n                                v-if=\"errors.copies\"\r\n                                v-text=\"errors.copies[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.format_printer }\"\r\n                        >\r\n                            <label class=\"control-label\">Tamaño hoja </label>\r\n                            <el-select\r\n                                v-model=\"form.format_printer\"\r\n                                slot=\"prepend\"\r\n                                placeholder=\"Seleccione el Tipo de Papel\"\r\n                            >\r\n                                <el-option\r\n                                    label=\"Tamaño A4\"\r\n                                    value=\"1\"\r\n                                ></el-option>\r\n                                <el-option\r\n                                    label=\"Tamaño A5\"\r\n                                    value=\"2\"\r\n                                ></el-option>\r\n                                <el-option\r\n                                    label=\"Tamaño Ticket 80MM\"\r\n                                    value=\"3\"\r\n                                ></el-option>\r\n                                <el-option\r\n                                    label=\"Tamaño Ticket 50MM\"\r\n                                    value=\"4\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"form-control-feedback\"\r\n                                v-if=\"errors.format_printer\"\r\n                                v-text=\"errors.format_printer[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n                <div class=\"row\">\r\n                    <div class=\"col-md-6\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.customer_id }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Cliente por defecto</label\r\n                            >\r\n                            <el-select\r\n                                v-model=\"form.customer_id\"\r\n                                slot=\"prepend\"\r\n                                @change=\"checkDocument\"\r\n                                placeholder=\"Seleccione el Cliente por defecto\"\r\n                            >\r\n                                <el-option\r\n                                    v-for=\"option in customers\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.name\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"form-control-feedback\"\r\n                                v-if=\"errors.customer_id\"\r\n                                v-text=\"errors.customer_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-6\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.document_default }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Comprobante por defecto</label\r\n                            >\r\n                            <el-select\r\n                                @change=\"checkDocument\"\r\n                                v-model=\"form.document_default\"\r\n                                slot=\"prepend\"\r\n                                placeholder=\"Seleccione el Comprobante\"\r\n                            >\r\n                                <el-option\r\n                                    label=\"FACTURA ELECTRÓNICA\"\r\n                                    value=\"01\"\r\n                                ></el-option>\r\n                                <el-option\r\n                                    label=\"BOLETA DE VENTA\"\r\n                                    value=\"03\"\r\n                                ></el-option>\r\n                                <el-option\r\n                                    label=\"NOTA DE VENTA\"\r\n                                    value=\"80\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"form-control-feedback\"\r\n                                v-if=\"errors.document_default\"\r\n                                v-text=\"errors.document_default[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-6\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.has_igv_31556 }\"\r\n                        >\r\n                            <el-checkbox v-model=\"form.has_igv_31556\">\r\n                                Sujeto al IGV - Ley 31556\r\n                            </el-checkbox>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n            <div class=\"form-actions text-end pt-2 pb-2\">\r\n                <el-button @click.prevent=\"close()\">Cancelar</el-button>\r\n                <el-button\r\n                    type=\"primary\"\r\n                    native-type=\"submit\"\r\n                    :loading=\"loading_submit\"\r\n                    >Guardar</el-button\r\n                >\r\n            </div>\r\n        </form>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\nexport default {\r\n    props: [\"showDialog\", \"recordId\"],\r\n    data() {\r\n        return {\r\n            loading_submit: false,\r\n            titleDialog: null,\r\n            resource: \"establishments\",\r\n            errors: {},\r\n            form: {},\r\n            countries: [],\r\n            all_departments: [],\r\n            all_provinces: [],\r\n            all_districts: [],\r\n            customers: [],\r\n            provinces: [],\r\n            districts: []\r\n        };\r\n    },\r\n    async created() {\r\n        await this.initForm();\r\n        await this.$http.get(`/${this.resource}/tables`).then(response => {\r\n            this.countries = response.data.countries;\r\n            this.all_departments = response.data.departments;\r\n            this.all_provinces = response.data.provinces;\r\n            this.customers = response.data.customers;\r\n            this.all_districts = response.data.districts;\r\n        });\r\n    },\r\n    mounted() {\r\n        //     console.log('res1');\r\n        //     qz.security.setCertificatePromise((resolve, reject) => {\r\n        //         this.$http.get('/api/qz/crt/override', {\r\n        //             responseType: 'text'\r\n        